import ArtGallery from "./components/ArtGallery/ArtGallery";
import Header from "./components/Header/Header";
import React, { useEffect } from "react";
import Tutorial from "./components/Tutorial/Tutorial.jsx";

import { BrowserRouter as Router, Switch, Route } from "react-router-dom";

import "./App.scss";
import "./fonts/pkmn-game.ttf";

function App() {
   useEffect(() => {
      document.title = "Silver Islands";
   });

   return (
      <div className="App">
         {/*<Router basename={"/silver-islands"}>*/}
         <Router>
            <Header />

            <main className="App-content">
               <Switch>
                  <Route path={`${process.env.PUBLIC_URL}/tutorial`}>
                     <Tutorial />
                  </Route>
                  <Route exact path={`${process.env.PUBLIC_URL}/`}>
                     <ArtGallery />
                  </Route>
                  <Route path="*">
                     <NoMatch />
                  </Route>
               </Switch>
            </main>
         </Router>
         <footer>
            All layouts, content, and custom images are © 2020 of The Silver
            Islands. None may be reproduced without permission. Pokemon is
            copyright © 2020 Nintendo GAME FREAK. This site is purely a fan made
            work and is in no way official.
         </footer>
      </div>
   );
}

function NoMatch() {
   return <h2>404 not found</h2>;
}

export default App;
