import React, { Component } from "react";

class Accordion extends Component {
   constructor(props) {
      super(props);
      this.state = {
         openStates: Array(this.props.children.length).fill(false),
      };
   }

   handleClick = (e, index) => {
      const newOpen = [...this.state.openStates];
      newOpen[index] = !this.state.openStates[index];
      this.setState({ openStates: newOpen });
   };

   render() {
      return (
         <div className="Accordion">
            {this.props.children.map((child, i) => {
               return (
                  <Section
                     key={i}
                     isOpen={this.state.openStates[i]}
                     onClick={(e) => this.handleClick(e, i)}
                  >
                     {child}
                  </Section>
               );
            })}
         </div>
      );
   }
}

function Section(props) {
   const {
      isOpen,
      onClick,
      children: {
         props: { title },
      },
   } = props;

   const collapsed = (
      <section className="AccordionSection-collapsed" onClick={onClick}>
         <span className="AccordionTitle">{title}</span>
      </section>
   );

   const expanded = (
      <section className="AccordionSection-expanded">
         <span className="AccordionTitle" onClick={onClick}>
            {title}
         </span>
         {props.children}
         <div className="collapseSection" onClick={onClick}>
            <span className="collapseText">collapse</span>
         </div>
      </section>
   );

   return isOpen ? expanded : collapsed;
}

export default Accordion;
